CREATE TABLE m_contract_template (id BIGINT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(200) NOT NULL,contract_type VARCHAR(30),html_content TEXT NOT NULL,version INT NOT NULL DEFAULT 1,active_flag TINYINT NOT NULL DEFAULT 1,created_by BIGINT,created_at DATETIME DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,deleted_flag TINYINT NOT NULL DEFAULT 0,INDEX idx_contract_tpl_type(contract_type)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE t_contract_document (id BIGINT AUTO_INCREMENT PRIMARY KEY,contract_id BIGINT NOT NULL,template_id BIGINT NOT NULL,template_version INT NOT NULL,rendered_html MEDIUMTEXT NOT NULL,pdf_path VARCHAR(500),pdf_sha256 CHAR(64),cloudsign_document_id VARCHAR(100),cloudsign_file_id VARCHAR(100),status VARCHAR(20) NOT NULL DEFAULT '下書き',recipient_name VARCHAR(100) NOT NULL,recipient_email VARCHAR(200) NOT NULL,signed_pdf_path VARCHAR(500),certificate_path VARCHAR(500),sent_at DATETIME,completed_at DATETIME,last_synced_at DATETIME,error_message VARCHAR(1000),created_at DATETIME DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,deleted_flag TINYINT NOT NULL DEFAULT 0,INDEX idx_contract_doc_contract(contract_id),CONSTRAINT fk_contract_doc_contract FOREIGN KEY(contract_id) REFERENCES t_contract(id),CONSTRAINT fk_contract_doc_template FOREIGN KEY(template_id) REFERENCES m_contract_template(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
